import { redirect } from '@sveltejs/kit';
import type { Cookies, RequestEvent } from '@sveltejs/kit';
import type { Departure, FulfillmentTaskList } from '$lib/features/s3-ops/types';

// $types is generated by svelte-kit sync; fall back to RequestEvent when not yet generated
type LoadEvent = { cookies: Cookies; fetch: RequestEvent['fetch'] };

const MOCK = process.env.VITE_MOCK_OPS === 'true';
// GATEWAY_URL must come first: set at runtime in docker-compose for SSR.
// VITE_GATEWAY_URL is baked at build time for the browser bundle, not available SSR.
const baseUrl =
  process.env.GATEWAY_URL ?? process.env.VITE_GATEWAY_URL ?? 'http://localhost:4000';

// Server-side mock — mirrors the client mock but uses process.env
async function loadMockData(): Promise<{ tasks: FulfillmentTaskList; departures: Departure[] }> {
  const { listFulfillmentTasksMock, MOCK_DEPARTURES } = await import(
    '$lib/features/s3-ops/mock'
  );
  const tasks = await listFulfillmentTasksMock({});
  return { tasks, departures: MOCK_DEPARTURES };
}

export const load = async ({ cookies, fetch }: LoadEvent) => {
  const accessToken = cookies.get('umrohos_access_token');
  if (!accessToken) {
    throw redirect(303, '/console/login');
  }

  if (MOCK) {
    const { tasks, departures } = await loadMockData();
    return { tasks: tasks.tasks, total: tasks.total, departures, error: null };
  }

  try {
    const [tasksRes, departuresRes] = await Promise.all([
      fetch(`${baseUrl}/v1/fulfillment-tasks`, {
        headers: { Authorization: `Bearer ${accessToken}` }
      }),
      fetch(`${baseUrl}/v1/departures?status=active`, {
        headers: { Authorization: `Bearer ${accessToken}` }
      })
    ]);

    const tasksBody = tasksRes.ok
      ? ((await tasksRes.json()) as FulfillmentTaskList)
      : { tasks: [], total: 0 };

    const departuresBody = departuresRes.ok
      ? ((await departuresRes.json()) as { departures: Departure[] })
      : { departures: [] };

    return {
      tasks: tasksBody.tasks ?? [],
      total: tasksBody.total ?? 0,
      departures: departuresBody.departures ?? [],
      error: tasksRes.ok ? null : `Gagal memuat data ops (${tasksRes.status})`
    };
  } catch {
    return { tasks: [], total: 0, departures: [], error: 'Tidak dapat terhubung ke gateway.' };
  }
};
